'use strict';

/**
 * cleanup-orphan-public-files.js
 *
 * Detects (and optionally removes) public article HTML files that exist on disk
 * but are NOT owned by git and NOT expected outputs of the current publication
 * transaction.  These are "escaped" files — generated by a tool outside the
 * publication-transaction boundary — that would appear as untracked artefacts
 * in git status and pollute a fresh CI checkout.
 *
 * Scoped to article publication routes only:
 *   market-outlook/*.html        (slug pages — not daily/, weekly/, not index.html)
 *   ar/market-outlook/*.html
 *   en/market-outlook/*.html
 *   intelligence/*.html
 *   ar/intelligence/*.html
 *   en/intelligence/*.html
 *   insights/*.html
 *   ar/insights/*.html
 *   en/insights/*.html
 *
 * Daily/weekly briefing pages (market-outlook/daily/, market-outlook/weekly/)
 * are treated as site-infrastructure and are handled by the commit step, not
 * the orphan cleaner.
 *
 * Modes:
 *   node cleanup-orphan-public-files.js              → dry-run: list orphans, exit 0
 *   node cleanup-orphan-public-files.js --check      → list orphans, exit 1 if any found
 *   node cleanup-orphan-public-files.js --execute    → delete orphans, exit 0 when done
 *
 * Usage:
 *   npm run check:no-orphan-public-files
 *   npm run cleanup:orphan-public-files
 */

const fs    = require('fs');
const path  = require('path');
const { execSync } = require('child_process');

const ROOT    = path.resolve(__dirname, '..');
const TX_PATH = path.join(ROOT, 'data', 'intelligence', 'publication-transaction.json');

const DRY_RUN = !process.argv.includes('--execute');
const CHECK   = process.argv.includes('--check');

// ── Article public routes to scan (direct children only, no subdirectory walk) ──

const ARTICLE_DIRS = [
  'market-outlook',
  'ar/market-outlook',
  'en/market-outlook',
  'intelligence',
  'ar/intelligence',
  'en/intelligence',
  'insights',
  'ar/insights',
  'en/insights',
];

// Filename pattern: slug pages look like `some-kebab-slug-2026-06-08.html`
// We exclude index.html and any file without a dash (safety guard for short names)
const SLUG_FILE_RE = /^[a-z0-9][a-z0-9-]+\.html$/;
const EXCLUDE_FILES = new Set(['index.html']);

// ── Helpers ──────────────────────────────────────────────────────────────────

function readJson(p) {
  try { return JSON.parse(fs.readFileSync(p, 'utf8')); } catch { return null; }
}

function getTrackedFiles() {
  try {
    const out = execSync('git ls-files', { cwd: ROOT, stdio: ['pipe', 'pipe', 'ignore'] }).toString();
    return new Set(out.split('\n').filter(Boolean).map(f => f.replace(/\\/g, '/')));
  } catch {
    return null;
  }
}

function getTransactionExpectedFiles() {
  const tx = readJson(TX_PATH);
  if (!tx) return new Set();
  const files = [
    ...(tx.expected_public_pages || []),
    ...(tx.files_created || []),
  ];
  return new Set(files.map(f => f.replace(/\\/g, '/')));
}

// Defense in depth: pages belonging to the article this run reports as
// published are never orphans, even if the transaction file is stale.
function getReportExpectedFiles() {
  const report = readJson(path.join(ROOT, 'data', 'intelligence', 'publishing-report.json'));
  if (!report || report.published !== true || !report.selected_topic) return new Set();
  let expected = [];
  try {
    const { expectedPublicPagesFor } = require('./publication-transaction');
    expected = expectedPublicPagesFor(report.selected_content_type, report.selected_topic);
  } catch { /* best-effort */ }
  return new Set(
    [...expected, ...(report.public_pages_created || [])].map(f => f.replace(/\\/g, '/'))
  );
}

// ── Scanner ──────────────────────────────────────────────────────────────────

function scanOrphans(trackedFiles, txExpected) {
  const orphans = [];

  for (const dir of ARTICLE_DIRS) {
    const absDir = path.join(ROOT, dir);
    if (!fs.existsSync(absDir)) continue;

    let entries;
    try { entries = fs.readdirSync(absDir); } catch { continue; }

    for (const file of entries) {
      if (!SLUG_FILE_RE.test(file)) continue;
      if (EXCLUDE_FILES.has(file)) continue;

      // Only direct children — skip if it's a subdirectory itself
      const absFile = path.join(absDir, file);
      try { if (!fs.statSync(absFile).isFile()) continue; } catch { continue; }

      const rel = `${dir}/${file}`;

      // Git-tracked → not an orphan
      if (trackedFiles && trackedFiles.has(rel)) continue;

      // Expected output of current transaction → about to be committed, not an orphan
      if (txExpected.has(rel)) continue;

      orphans.push(rel);
    }
  }

  return orphans.sort();
}

// ── Main ─────────────────────────────────────────────────────────────────────

function main() {
  const mode = CHECK ? 'check' : DRY_RUN ? 'dry-run' : 'execute';
  console.log(`[cleanup-orphan-public-files] mode=${mode}`);

  const trackedFiles = getTrackedFiles();
  if (trackedFiles === null) {
    console.log('[cleanup-orphan-public-files] git unavailable — skipping');
    process.exit(0);
  }

  const txExpected = getTransactionExpectedFiles();
  for (const rel of getReportExpectedFiles()) txExpected.add(rel);
  if (txExpected.size > 0) {
    console.log(`[cleanup-orphan-public-files] transaction/report has ${txExpected.size} expected output(s) — those are excluded from orphan detection`);
  }

  const orphans = scanOrphans(trackedFiles, txExpected);

  if (orphans.length === 0) {
    console.log('[cleanup-orphan-public-files] No orphan public article files found.');
    process.exit(0);
  }

  console.log(`[cleanup-orphan-public-files] ${orphans.length} orphan public article file(s) found:`);
  for (const rel of orphans) {
    console.log(`  ${DRY_RUN ? 'would remove' : 'removing'}: ${rel}`);
  }

  if (DRY_RUN) {
    if (CHECK) {
      console.error('[FAIL] Orphan public article files detected — run cleanup:orphan-public-files to remove, or investigate root cause.');
      process.exit(1);
    }
    console.log('[cleanup-orphan-public-files] Dry-run complete. Pass --execute to delete.');
    process.exit(0);
  }

  // Execute: delete orphans
  let removed = 0;
  let failed  = 0;
  for (const rel of orphans) {
    try {
      fs.unlinkSync(path.join(ROOT, rel));
      console.log(`  removed: ${rel}`);
      removed++;
    } catch (err) {
      console.error(`  ERROR removing ${rel}: ${err.message}`);
      failed++;
    }
  }

  console.log(`[cleanup-orphan-public-files] Removed ${removed} orphan file(s).${failed ? ` ${failed} failure(s).` : ''}`);
  if (failed > 0) process.exit(1);
}

main();
